from flask import Blueprint, request, jsonify
from yourapp.models import User
from yourapp.utils import current_user
from werkzeug.security import generate_password_hash

update_profile = Blueprint('update_profile', __name__)

@update_profile.route('/profile/update', methods=['PATCH'])
def update_profile_endpoint():
    data = request.json
    allowed_fields = ['email', 'username', 'account_type', 'credits', 'referral_code', 'verified_status']

    for field in data:
        if field not in allowed_fields:
            return jsonify({'error': f'Invalid field: {field}'}), 400

    current_user.email = data.get('email')
    current_user.username = data.get('username')
    current_user.account_type = data.get('account_type')
    current_user.credits = data.get('credits', type=int)
    current_user.referral_code = data.get('referral_code')
    current_user.verified_status = data.get('verified_status')

    current_user.save()

    return jsonify({'message': 'Profile updated successfully'}), 200